create table maxprint_dev.simple_purchase_item (
    id          number generated by default on null as identity not null enable,
    name        varchar2(100 byte),
    creation    timestamp(9),
    modified    timestamp(9),
    modified_by varchar2(50 byte),
    owner       varchar2(50 byte),
    docstatus   number,
    idx         number,
    account     varchar2(255 byte),
    amount      number,
    description varchar2(4000 byte),
    cost_center varchar2(50 byte),
    party_type  varchar2(50 byte),
    party       varchar2(255 byte),
    parent      varchar2(50 byte),
    parentfield varchar2(50 byte),
    parenttype  varchar2(50 byte)
);

alter table maxprint_dev.simple_purchase_item add primary key ( id )
    using index enable;


